import React, { useState } from 'react';
import { elementsMap, hashCode, intToRGB } from './common';

const Note = ({ i, j, note, sound, sheet, mod, volume }) => {
  const id = `${i}:${j}`;
  const imported = sheet[id] || null;
  const [delay, setDelay] = useState(imported ? imported.delay : 0.1);
  const [size, setSize] = useState(
    imported && imported.delay > 0.1 ? imported.delay * 2 + 1 : 1
  );
  const [opacity, setOpacity] = useState(imported ? '1' : '0.1');
  const [color] = useState('#' + intToRGB(hashCode(note + '1230')));

  // const [focus, setFocus] = useState(!!imported);
  if (imported) {
    sheet[id] = { value: note, delay: delay, x: i, y: j };
  }
  return (
    <div className="note">
      <button
        style={{ opacity }}
        ref={element => {
          if (i < mod) {
            elementsMap.set(id, element);
          }
        }}
        className="note-button"
        id={id}
        onKeyPress={e => {
          if (e.key === '=') {
            setDelay(Math.max(0.1, delay + 0.05));
            setSize(delay * 2 + 1);
          } else if (e.key === '-') {
            setDelay(Math.max(0.1, delay - 0.05));
            setSize(delay * 2 + 1);
          }
        }}
        onClick={() => {
          const id = `${i}:${j}`;
          if (sheet[id]) {
            setOpacity('0.1');
            delete sheet[id];
          } else {
            setOpacity('1');
            sound.volume.value = volume - 30;
            sound.triggerAttackRelease(note, delay);
            sheet[id] = { value: note, delay: delay, x: i, y: j };
          }
        }}
      >
        <div
          style={{
            transform: `scale(${size})`,
            backgroundColor: color
          }}
          className="shape"
        ></div>
      </button>
    </div>
  );
};
export default Note;
